INSERT INTO `article` (`artcl_id`, `artcl_title_bg`, `artcl_title_en`, `actl_resume_bg`, `actl_resume_en`, `artcl_autor_bg`, `artcl_autor_en`, `artcl_filename`, `artcl_magazine_id`, `artcl_count`) VALUES
  ('1', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ПРОУЧВАНИЯ ВЪРХУ РАСТЕЖА НА РАЗЛИЧНИ ПРОИЗХОДИ НА ОБИКНОВЕНА ЕЛА (<em>ABIES ALBA </em>MILL.) В ОПИТНИ ЕКОЛОГИЧНИ КУЛТУРИ</span></span></p>', '<p>\r\n	<span style=\"font-size: small\"><span style=\"font-family: Tahoma\">INVESTIGATIONS IN THE SILVER FIR (<em>ABIES ALBA </em>MILL.) ECOLOGICAL EXPERIMENTAL PROVENANCE AND PROGENIE TRIALS</span></span></p>\r\n', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">За получената информация са използвани резултати от стъблени анализи на средни доминиращи и средни моделни стъбла.<br>Потомствата на кандидат-елитните елови дървета от произход Славянка се характеризират с ясно открояваща се доминанта в растежа си. Тази тенденция се наблюдава и в годините на предишни измервания, но се запазва и досега, като е характерна за експериментите в Родопите и Странджа планина. Обяснението на този факт, а именно, по-високата жизненост и продуктивност вероятно се корени далеч назад във времето и е свързано с дългия и сложен формообразувателен процес на еловите популации.<br>Направените изследвания разкриват много добрата приспособимост на всички произходи от експеримента към климатичните условия в Странджа планина, където ела не се среща. Този интересен факт за пореден път потвърждава адаптивността на елата и високата норма на реакция към по-широк спектър от условия на средата.<br>В ДГС „Старо Оряхово” фиданките от кипиловския произход в експерименталната култура са с най-добри растежни показатели в годината на изследването. Тази популация в естествени условия се развива на около 450 m н.в. в Стара планина, поради тази причина вероятно е с очаквано най-висока възможност за приспособяване и развитие при климатичните условия, характерни за района. Изхождайки от биологията на вида, интерес в бъдеще ще представлява изменението на таксационните показатели след кулминацията в растежа на произходите.<br>Създадените обекти са предпоставка за запазването на ценния генофонд, както и възстановяване и разширяване границите на естествения ареал на елите в България.</span></span></p>', '<p style=\"text-align: justify;\">\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">The paper presents results of a study on progeny tests of Silver fir (Abies alba Mill.)<br />\r\n	established on four sites. Stem analysis of dominating and average model stems was used for<br />\r\n	comparison of the half-sib families. The progenies originating from Slavyanka Mts showed<br />\r\n	the best height growth. These results confirm the trend established in previous experiments<br />\r\n	and is well expressed in the experiments in Strandzha and Rhodopes. All the provenances<br />\r\n	showed good adaptation to the conditions in Strandzha Mountains and this fact confirmed<br />\r\n	the broad adaptation capacity of the Silver Fir. At Staro Oryahovo test site the provenance<br />\r\n	Kipilovo (450 m a.s.l.) showed the best performance. The tests proved to be good opportunity<br />\r\n	for studying the provenance/progeny performance and for ex situ conservation of the valuable<br />\r\n	gene pool in Bulgaria.</span></span></p>\r\n', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Иван Евтимов, Величко Гагов</span></span></p>', '<p>\r\n	<span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Ivan Evtimov, Velitchko Gagov</span></span></p>\r\n', '1-2_2008_1.pdf', '1', '5'),
  ('2', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ФЛОРНИ ЕЛЕМЕНТИ И БИОЛОГИЧЕН СПЕКТЪР НА ГОРИ С ПРЕОБЛАДАВАНЕ НА КОСМАТ ДЪБ (<em>QUERCUS PUBESCENS</em> WILLD.) В ЗАПАДНИТЕГРАНИЧНИ ПЛАНИНИ</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">FLORISTIC ELEMENTS AND BIOLOGICAL SPECTRUM OF FORESTS DOMINATED BY PUBESCENT OAK (<em>QUERCUS PUBESCENS </em>WILLD.) IN THE WEST FRONTIER MOUNTAINS</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">При проведени фитоценотични проучвания на гори с преобладаване на космат дъб в планините Огражден, Малeшевска и Влахина, които според флористичното райониране на България се отнасят към район Западни гранични планини, през периода 2005–2008 г. са установени 327 вида висши растения. Те се отнасят към 205 рода и 54 семейства. В резултат на силно изразеното антропогенно въздействие (сечи, паша и клоносечно стопанисване), флористичният състав и фитоценотичната структура на горите с преобладаване на космат дъб в този район са значително променени. Въз основа на жизнените форми на растенията и фитогеографската принадлежност на растителните видове са определени биологичният и фитогеографският спектър на проучваните дъбови гори. Чрез сравнителен анализ на установения биологичен спектър на съвременните горски съобщества с преобладаване на космат дъб в проучвания район и биологичните спектри на горски съобщества в други географски райони и в други типове растителност са очертани общите насоки на протичащите вторични сукцесии на растителността. Анализирано е и съотношението на флорните елементи в растителни съобщества в различни фази на сукцесии. Резултатите от проведеното проучване дава възможност да се направи заключението, че биологичният спектър и съотношението на флорни елементи в отделните групи растителни съобщества могат да се използуват като комплексни индикатори за оценка на съвременното състояние и за насоките на протичащите сукцесии в горите с преобладаване на космат дъб в проучвания район.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">A total of 327 species have been found in the period 2005-2008 during the phytosociological<br>research in the forests, dominated by Pubescent Oak in the mountains Ogragden, Malashevo<br>and Vlahina, which belong to the West Frontier Mountains floristic region. They belong to 205<br>genera and 54 families. As a result of strong anthropogenic influence (clear felling, grazing<br>and brunch cutting management), the floristic composition and phytosociologic structure are<br>considerably changed. The biological and phytogeographic spectrum was determined on the<br>basis of life forms and phytogeographic affiliation of the plant species. The general trends of<br>secondary successions were outlined by comparative analysis of biological spectrum of the<br>studied contemporary Pubescent Oak dominated forests and the spectra of communities from<br>other geographic regions. The relationship between floristic elements in plant communities<br>at different stages of the successions was analyzed too. Results allow the conclusion that<br>the relationships between biological spectrum and floristic elements in different plant<br>communities can be used as a complex indicator for the recent status and general trends of<br>successions in the Pubescent Oak dominated forests.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Георги Гогушев</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Georgi Gogushev</span></span>&lt;</p>', '1-2_2008_2.pdf', '1', '2'),
  ('3', '<p>ВЪЗСТАНОВЯВАНЕ НА ОПОЖАРЕНИ ГОРСКИ ПЛОЩИ НА ТЕРИТОРИЯТА НА ДГС \"ШИРОКА ЛЪКА\" И ДГС \"ИВАЙЛОВГРАД\"</p>', '<p>\r\n	RESTORATION OF BURNED FOREST AREAS ON THE TERRITORY OF SHIROKA LAKA AND IVAILOVGRAD STATE FOREST ENTERPRISES</p>\r\n', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Проучени са възможности за изкуствено възобновяване на горски площи, засегнати<br>от пожари в естествени смърчови и дъбови гори на територията на ДГС „Широка лъка“<br>и ДГС „Ивайловград“. Проследявани са следните показатели: процент на прихващане<br>и оцеляване и прираст по височина на фиданките.<br>Залесителният опит в ДГС „Широка лъка“ е заложен през пролетта на 2002 г.<br>Залесяването е извършено с 2-годишни семенищни фиданки от обикновен смърч в 2<br>повторения и 3 варианта на почвоподготовка – ръчни тераси, площадки и опростена<br>почвоподготовка. Най-висок процент на оцеляване и прираст по височина са отчетени<br>във варианта на садене в ръчни тераси.<br>Залесителният опит в ДГС „Ивайловград“ е заложен през пролетта на 2004 г. с черен<br>бор и цер. При черния бор е извършено садене на 2-годишни семенищни фиданки, а<br>при цера е използвано както садене на едногодишни фиданки, така и посев на жълъди.<br>Залесяването е извършено в 2 повторения при пълна почвоподготовка и 2 варианта на<br>садене (с подобрен меч на Колесов и садилен кол). Най-висок процент на оцеляване се<br>установява за цера във варианта на садене с подобрен меч на Колесов, а в растежа по<br>височина както при цера, така и при черн</span></span></p>', '<p>\r\n	<span style=\"font-size: small\"><span style=\"font-family: Tahoma\">The opportunities for restoration of burned natural spruce and oak forests, located on the territory of the Shiroka laka and Ivailovgrad State Forest Enterprises respectively, were studied. The following indicators were measured and calculated: percentage of the established seedlings, percentage of survival of the seedlings, as well as height growth.<br />\r\n	The experimental planting in the Shiroka laka State Forest Enterprises was made in the spring of 2002. 2-years old seedlings of Norway Spruce (Picea abies (L.) Karst.) were used for the reforestation process. The experimental planting was made in 2 repeats and 3 types of soil preparation (hand-made terraces, small square fields and simplified soil preparation). The highest percentage of survival and highest height growth were reported for the variant of panting in the hand-made terraces.<br />\r\n	Seedlings of Austrian Pine (Pinus nigra Arn.) and Turkey Oak (Quercus cerris L.) were used for the experimental planting in Ivailovgrad State Forest Enterprises, which was made in the spring of 2004. 2-years old seedlings of Austrian Pine, 1-year old seedlings and seeds of Turkey Oak were used for the planting. The experimental planting was made in 2 repeats, 2 types of planting (using improved Kolesov sword and planting stake) and with deep soil preparation. The highest percentage of survival was determined for the variant of planting with the improved Kolesov sword. The height growth of the Austrian Pine and Turkey Oak seedlings did not revealed significant differences for the different variants of planting.</span></span></p>\r\n', '<p>Красимира Петкова, Александър Ташев, Латинка Тодорова</p>', '<p>\r\n	Krasimira Petkova, Alexander Tashev, Latinka Topalova-Rzerzycha</p>\r\n', '1-2_2008_3.pdf', '1', '1'),
  ('4', 'КИСЕЛ ДРЕНАЖ НА НАСИПНИ СУБСТРАТИ ОТ ДОБИВ НА ОЛОВНО-ЦИНКОВА РУДА', '<p>\r\n	ACID ROCK DRAINAGE FROM SUBSTRATA OF PB-ZN ORE PRODUCTION</p>\r\n', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Изследванията са проведени в три закрити за експлоатация рудници на „Горубсо–Мадан”. Извършени са анализи на скални насипни субстрати за определяне на фракционния състав и съдържанието на обща сяра и нейните форми (сулфидна и сулфатна), тежки метали (общи и подвижни форми) и активна киселинност. Направен е статичен прогнозен тест. Изведен е хумиден тест с монолити от изследваните субстрати и е определен химичния състав на инфилтрираните води.<br>Установено е, че фракционният състав на насипните субстрати осигурява различни условия за окисление и дрениране. Значима част от насипните субстрати се характеризират с концентрации на Pb, Zn, As и Cd над максимално допустимите и интервенционните концентрации. Доказано е, че Pb, Zn, Mn и Cd са по-подвижни и се срещнат във високи концентрации, за разлика от арсена и желязото. В състава на общата сяра преобладаващо участие има сулфидната сяра и по-слабо сулфатната окислена сулфидна сяра. Определени са киселинният потенциал (АР), неутрализационният потенциал (NP) и коефициентът на неутрализационния потенциал (NPR), даващ прогноза за потенциала за генериране на кисел дренаж.<br>В опитни условия е доказано замърсяването на получения инфилтрат с тежки метали, сулфати и слаба промяната в значенията на рН в посока вкисляване.</span></span></p>', '<p>\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Studies were conducted in three operating mines closed in Gorubso-Madan. Were carried<br />\r\n	out bulk analysis of rock substrates for determining the composition and fraction of total<br />\r\n	sulfur content and its forms (sulphate and sulphide), heavy metals (total and mobile forms)<br />\r\n	and active acidity. Forecast is made static test. Fate is humiden test monoliths of substrates<br />\r\n	examined and determined the chemical composition of infiltration water.<br />\r\n	It was found that the fraction composition of the bulk substrates provide different<br />\r\n	conditions for oxidation and drainage. Important part of the bulk substrates are characterized<br />\r\n	by concentrations of Pb, Zn, As and Cd than the maximum and permissible concentrations<br />\r\n	and intervention. It has been shown that Pb, Zn, Mn and Cd are more mobile and meet<br />\r\n	at high concentrations, in contrast to arsenic and iron. In the composition of total sulfur<br />\r\n	is predominantly involved sulphide sulfur and less sulphate sulphide oxidized sulfur. Are<br />\r\n	determined acid potential (AP), neutralization potential (NP) and neutralization potential<br />\r\n	ratio (NPR), giving an estimate of the potential to generate acid drainage. In the experimental<br />\r\n	conditions is shown the resulting leachate pollution with heavy metals, sulphates and weak<br />\r\n	meanings change in pH towards acidity.</span></span></p>\r\n', 'Росица Петрова', '<p>\r\n	Rossitsa Petrova</p>\r\n', '1-2_2008_4.pdf', '1', '0'),
  ('5', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">АНАЛИЗ И ОЦЕНКА НА ПОЖАРИТЕ И ПОЖАРНАТА ОПАСНОСТ В ГОРИТЕ</span></span></p>', '<p>\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">ANALYSIS AND ASSESSMENT OF FOREST FIRES AND FIRE HAZARD</span></span></p>\r\n', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Извършен е анализ на пожарната активност в нашите гори за периода 1991–2008 г. На базата на резултатите от анализа са направени следните изводи: 1) Общата тенденция на пожарната активност в нашите гори е устойчива и перманентна и няма основание да се смята, че може да има връщане към ситуацията от близкото минало; 2) Налице е ясно изразена цикличност на пожарната активност в горите, като максималните `и стойности се редуват през 7 календарни години; 3) Причините за възникването на горските пожари у нас в над 90 % от случаите са резултат от човешка дейност; 4) Предложеният общ показател за определяне на пожарната опасност в горите по реализираните `и стойности за определен период с достатъчна за практиката надеждност, може да се използва успешно в цялостната дейност на горските и противопожарните служби по управлението на горските пожари.</span></span></p>', '<p>\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">An analysis is made of the fire activity in the Bulgarian forests for the period 1991 –<br />\r\n	2008. On the basis of the results of this analysis the following conclusions are drawn: 1) The<br />\r\n	common trend of fire activity in the Bulgarian forests is steady and permanent, so there are<br />\r\n	no grounds to consider a turn back to the near past situation possible. 2) A clearly expressed<br />\r\n	cyclic recurrence of forest fire activity exists; the maximum values succeed each other evenly<br />\r\n	at intervals of 7 years. 3) Causes for forest fires in the country in over 90 % of the cases<br />\r\n	are a result of human activities. 4) The proposed general indicator for forest fire hazard<br />\r\n	assessment by its realized values for a given period, sufficiently reliable for the practice, can<br />\r\n	be successfully used in the entire activity of forest services and fire departments referring to<br />\r\n	management of forest fires.</span></span></p>\r\n', '<p>Кирил Любенов, Владимир Константинов</p>', '<p>\r\n	Kiril Lyubenov, Vladimir Konstantinov</p>\r\n', '1-2_2008_5.pdf', '1', '0'),
  ('6', '<p>ПРОДУКТИВНОСТ НА ФЕРМЕРНО ОТГЛЕЖДАНИ ПОЛСКИ ЯРЕБИЦИ (<em>PERDIX PERDIX </em>L.)В ЗАВИСИМОСТ ОТ НЯКОИ ФАКТОРИ НА СРЕДАТА</p>', '<p>PRODUCTIVITY OF FARM-REARED GREY PARTRIDGES (<em>PERDIX PERDIX </em>L.) IN RELATION WITH SOME ECOLOGICAL VARIABLES</p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Две групи, всяка от по двадесет и четири двойки полово зрели полски яребици, са поставени в индивидуални клетки за снасяне на затревена земя (едната група) и в малки клетки с под от мрежа над земята (другата група). Продуктивността на птиците е статистически значимо по-висока върху затревена земя. Установена е достоверна положителна корелативна зависимост между средния дневен добив на яйца и екологичните променливи – продължителност на фотопериода и температурата на въздуха – и в двата типа клетки. Обсъждат се възможности за увеличаване на добива на яйца от полските яребици чрез опитимизация на клетъчните конструкции и изкуствено удължаване на фотопериода.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Two groups, each one of twelve pairs of mature grey partridges, have been kept in individual laying pens on grass (group one) and in small wire-floored pens (group two). Egg productivity has been significantly higher on grass. The daily egg yield has been positively and significantly correlated with the number of daylight hours and with air temperature in both pen types. Opportunities for increasing egg yield by optimization of pen construction as well as by increasing the number of daylight hours, have been discussed.</span></span></p>', '<p>Звезделин Миланов</p>', '<p>Zvezdelin Milanov</p>', '1-2_2008_6.pdf', '1', '0'),
  ('7', '<p>ИЗСЛЕДВАНЕ НА РАБОТАТА НА МАЛОГАБАРИТЕН ОБЕЗКРИЛИТЕЛ ЗА ОБРАБОТКА НА СЕМЕНА ОТ ЧЕРЕН БОР (<em>PINUS NIGRA </em>ARN.) И ОБИКНОВЕН СМЪРЧ (<em>PICEA ABIES</em> KARST.)</p>', '<p>EXPLORATION OF THE DEWINGING PROCESS ON BLACK PINE (<em>PUNUS NIGRA </em>ARN) AND NORWAY SPRUCE (<em>PICEA ABIES</em> KARST) SEEDS WITH SMALL DIMENSION DEWINGER</p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">В настоящата работа е проведено изследване върху работата на малогабаритен обезкрилител. Няколко такива машини бяха разработени от наши специалисти. Те са създадени на базата на оригинална конструкция от палцеви обезкрилители от модела „Liliput”, произведени в Германия (Хамбург) и широко използвани в европейските страни. Така произведените обезкрилители са финансирани от националното ни горско ведомство, като са предвидени за работа в регионалните семедобивни и семеконтролни станции. Обезкрилителят е предназначен за преработка на малки партиди (до 10 kg), основно за семена от иглолистни видове. Като се отчете тенденцията за намаляване на количеството семена в партидите през последните години, този тип обезкрилители са актуални за нашето семепроизводство. За съжаление те и до ден днешен не работят или използват по предназначение. Една от основните причини за това се дължи на липсата на инструкция за експлоатация и указания за определяне на параметрите и режимите им на работа.<br>За решаване на този проблем в настоящата работа е проведено експериментално изследване за установяване на ефективни и оптимални режими при обезкриляване на семена от черен бор и обикновен смърч с този тип машини. В резултат на това изследване са получени важни резултати относно качествените и количествените показатели при работа на машината. Въз основа на това са построени зависимости, изразяващи взаимовръзката на изследваните параметри. От тези зависимости са установени функционалните режими, при които се получават висококачествени семена. На тази основа са изведени и предложени оптимални режими за работа и управление на процеса. Получените резултати имат научен и практичен характер, с приложение в областта на горското семепроизводство и могат да се използват в семедобивните и семеконтролните станции у нас.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">In the present work experimental investigation on the process of dewinging of black pine and Norway spruce seeds with small dimension dewinger was performed and the optimal working regimes were established. As result of this work important results were obtained referring to qualitative and quantitative indexes for different working regimes of the machine.<br>On this base correlations, expressing the relationship among the investigated parameters,<br>were established. Functional regimes for production of high quality seeds were determined<br>by these correlations. On this base optimal regimes for functioning of the machine and<br>management of the process are extracted and proposed. The results received are addressed to<br>be applied in the field of forest seed production.</span></span></p>', '<p>Константин Маринов1, Димитър Ненов, Сотир Глушков</p>', '<p>Konstantin Marinov, Dimitar Nenov1, Sotir Glushkov</p>', '1-2_2008_7.pdf', '1', '0'),
  ('8', 'ЕКСПЕРИМЕНТАЛНИ МЕТОДИ ЗА ИЗСЛЕДВАНЕ НА ЕФЕКТА ОТ ТРОПОСФЕРЕН ОЗОН ВЪРХУ ГОРСКИ ЕКОСИСТЕМИ', 'EXPERIMENTAL METHODS FOR ASSESSMENT OF TROPOSPHERIC\r\nOZONE EFFECT ON FOREST ECOSYSTEMS', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Направен е преглед на най-прилаганите експериментални методи и съоръжения за мониторинг и изследване на влиянието на тропосферния озон върху горски екосистеми при контролирани, полу-контролирани и полеви условия. Описани са предимствата и недостатъците на използваните в световната практика опитни постановки. Изброени са някои от най-популярните биоиндикаторни видове за действието на озона. Коменирани са факторите на околната среда, които повлияват реакцията на растенията към действието на озона. Направени са препоръки относно необходимостта от системен подход за екологичните изследвания в горски екосистеми.</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">A review is made of the most often applied experimental methods and equipments for studies of troposheric ozone in forest ecosystems at controlled, semi-controlled and field conditions. The advantages and shortcomings of the experimental treatments used in the world practice are estimated. Some of conventional plant species used as bioindicators for ozone action is presented. The most important environmental factors, affecting plant’s response to ozone, are discussed. Recommendations are made for method approach in the ecological studies of forest ecosystems.</span></span></p>', 'Петя Първанова, Николина Цветкова, Светла Братанова-Дончева,Радка Фикова, Светослав Анев', 'P. Parvanova, N. Tzvetkova, Sv. Bratanova-Doncheva, R. Fikova1, Sv. Anev', '1-2_2008_8.pdf', '1', '0'),
  ('9', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ПРОУЧВАНИЯ ВЪРХУ РАСТЕЖА НА ПОТОМСТВА ОТ СВОБОДНО ОПРАШВАНЕ НА ОБИКНОВЕНАТА ЕЛА (<em>ABIES ALBA</em> MILL.) И ЦАР-БОРИСОВАТА ЕЛА (<em>ABIES BORISII-REGIS </em>MATTF.)</span></span></p>', '<p>\r\n	<span style=\"font-size: small\"><span style=\"font-family: Tahoma\">INVESTIGATIONS ON THE OPEN POLLINATED TREE PROGENIES OF THE FIR SPECIES (<em>ABIES ALBA </em>MILL.)<br />\r\n	AND (<em>ABIES BORISII-REGIS</em> MATTF.)</span></span></p>\r\n', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Представеното изследване има за цел проучване на потомствените опитни култури, създадени в района на ДГС „Старо Оряхово” през 1989, 1992 и 1993 година с фиданки от автохтонни полусибови потомства на кандидателитните дървета, включени във вегетативната семепроизводствена градина, разположена на територията на стопанството.<br>На изготвените диаграми е представен темпът на растеж и прираст при отделните потомства от различните произходи.<br>Направено е сравнение между открояващи се най-бързо растящи и с най-висока жизненост потомства – от произход Славянка, Родопи, както и такива със средни показатели – някои потомства от Рила, Осоговска и Малашевска планина.<br>Различията, които съществуват в рамките на отделните години са обусловени от наследствено закрепената норма на реакция към промените на екологичните условия, от което следва, че са необходими по-продължителни проучвания на горско-дървесните видове.<br>При всички потомства се забелязва ясна тенденция за увеличаване на средния годишен височинен прираст от 2000 до 2005 г.<br>В резултат на кръстосаното опрашване във вегетативната семепроизводствена градина, фиданките от отделните майчини дървета се отличават с почти два пъти по-бърз растеж от фиданките, получени от същите майчини дървета в автохтонните популации.<br>Получените досега резултати определят значението на индивидуалната селекция при обикновената ела.</span></span></p>', '<p>\r\n	<span style=\"font-size: small\"><span style=\"font-family: Tahoma\">The study aims at studying of the progeny tests established in the region of Staro Oryahovo in 1989, 1992 and 1993 using half-sib families of the plus trees included in the seed orchard in the same region. Ranking of progenies revealed a group of best performing ones from Slavyanka and Rhodopes, and some moderately performing, originating from the mountains Rila, Osogovo and Maleshevska. All the progenies showed a clear trend for increasing of the annual height increment in the period 2000-2005. The comparison between the performanceof the same progenies originating, first, from plus trees growing in natural stands, and second, from the clones in the seed orchard, taken from the same trees revealed that the latter had significantly better growth. The results point out the importance of individual selection in the<br />\r\n	breeding of Silver Fir.</span></span></p>\r\n', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Величко Гагов, Иван Евтимов</span></span></p>', '<p>\r\n	<span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Velitchko Gagov, Ivan Evtimov&lt;</span></span></p>\r\n', '1-2_2007_1.pdf', '2', '2'),
  ('10', '<p><span style=\"font-family: Tahoma\"><span style=\"font-size: small\">ИЗПОЛЗВАНЕ НА СЕЛЕКТИВНИ ХЕРБИЦИДИ ПРИ ПРОИЗВОДСТВО НА ФИДАНКИ ОТ ЧЕРЕН БОР (<em>PINUS NIGRA </em>L.)</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">THE USE OF SELECTIVE HERBICIDES IN THE PRODUCTION OF BLACK PINE SEEDLINGS (<em>PINUS NIGRA </em>L.)</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Черният бор е един от най-широко използваните иглолистни видове за залесяване в България. Производството на фиданки в горските разсадници изостава в технологично отношение. Едно от най-трудоемките агротехнически мероприятия е борбата с плевелната растителност в семенищата. Прилага се главно механичен контрол върху плевелите и не се използват химични средства. Чрез настоящото проучване е потърсена възможност за използване на селективни хербициди. Доказано е, че ефективна борба срещу плевелната растителност в семенищата от черен бор може да се води чрез използването на воден разтвор на хербицидите „Гоал 2Е” – концентрация 2 ml/l или „Тарга супрер 5 ЕК” – 2,5 ml/l. Посочените хербициди имат подчертано селективно действие и могат да бъдат използвани по времето на всички фенологични състояния. Използването на изпитаните хербициди позволява развитието на по-голям прираст при третираните фиданки в резултат на задържащото си действие по отношение на плевелната растителност.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">The black pine is one of the most widely afforestated coniferous species in Bulgaria. The production of black pine seedlings in the forest nurseries drop behind from technological point of view. One of the hardiest agronomic projects is the weed control in the seedbeds. The mechanical weed control is mainly used, as chemicals are not usually used. The aim of the present study is to determinate the potentialities of the selective herbicides. It has been proved that the effective weed control in the black pine seedbeds can be done by water solution of the following herbicides: GOAL 2E - 2 ml/l concentration or TARGA SUPER 5<br>ЕК – 2,5 ml/l. The given herbicides have pointedly selective effect and could be used all over the year. The use of the studied herbicides leads to higher seedlings growth as a result of the retentive effect over the weeds.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Наско Илиев</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Nasko Iliev</span></span></p>', '1-2_2007_2.pdf', '2', '1'),
  ('11', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">СЪСТОЯНИЕ, РАСТЕЖ И ПРОИЗВОДИТЕЛНОСТ НА ГОРСКИ КУЛТУРИ ОТ ОБИКНОВЕНА ЧЕРЕША (<em>PRUNUS AVIUM</em> L.)</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">STATE, GROWTH AND PRODUCTIVITY OF WILD CHERRY (<em>PRUNUS AVIUM</em> L.) FOREST PLANTATIONS</span></span></p>', '<p><span style=\"font-family: Tahoma\"><span style=\"font-size: small\">В нашата страна няма проучвания относно възможностите за създаване на горски култури от обикновена череша. Целта на настоящата работа е да се проучи лесокултурният опит с обикновена череша у нас и да се докажат производствените възможности и стопанската ценност на създадените култури от нея. Проучването визира европейския опит по създаването и стопанисването на култури от обикновена череша. Въз основа на получените резултати са препоръчани подходящи месторастения, първоначална гъстота на залесяване и подходящи видове за смесване. Представени са данни за производствените възможности на културите.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">There are no scientific researches on the possibilities for establishing pure wild cherry plantations or mixed ones with wild cherry as a main species. The aim of the present work is to study the wild cherry afforestation practices in the country and to prove the production possibilities of such plantations as<br>well as to show their value. The study reviews the European experience in establishing and managing of wild cherry plantations. Based on the obtained results appropriate sites are recommended as well as planting densities and suitable tree species for mixed plantations. Data for the production capacity of<br>plantations are presented.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Наско Илиев, Анна Петракиева, </span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Nasko Iliev, Anna Petrakieva, </span></span></p>', '1-2_2007_3.pdf', '2', '0'),
  ('12', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">ИЗСЛЕДВАНЕ НА ПРИПЛЪЗВАНЕТО НА СЕМЕНА ОТ ГОРСКО ДЪРВЕСНИ ВИДОВЕ В ШНЕКОВИТЕ АПАРАТИ НА ОБЕЗКРИЛЯВАЩИТЕ МАШИНИ</span></span></p>', '<p>\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">STUDY OF THE SLIPPING OF FOREST SPECIES SEEDS IN THE SCREW APPARATUS OF UNCEASING DEWINGERS</span></span></p>\r\n', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Добивът на качествени семена от горско дървесни видове е в основата на лесокултурната дейност на горското ни стопанство. От ефективното провеждане на тази дейност зависи крайното качество и себестойността на посевния материал.<br>При производството на семена от иглолистни дървесни видове се прилага преработка за отделяне на крилцата от семенната обвивка. Тази дейност е трудоемка и налага използване на специализирани технологични машини. В районните семедобивни в нашата страна приоритетно се използват палцевите сухи обезкрилители с непрекъснато действие. Приплъзването на семената в работните органи на тези машини е характерен процес по време на обезкриляването. По-голямата степен на приплъзване увеличава притриващите въздействия върху семената и повишава степента на обезкриляване, но намалява операционната производителност на процеса.<br>В настоящата работа е проведено теоретично и експериментално изследване за установяване параметрите (коефициентите) на приплъзване при семена от бял бор (Pinus silvestris L.), черен бор (Pinus nigra Arn. (P. Laricio Poir.)) и обикновен смърч (Picea excelsa Link). Коефициентите са определени във функция от големината на създаденото върху семената налягане и честотата на въртене на шнека. Получените коефициенти се използват непосредствено в емпирични уравнения за определяне на операционната производителност на процеса. Изследването е проведено с обезкриляваща машина в горска семедобивна станция – гр. Разлог. Резултатите са представени във вид на графични зависимости. Коефициентите на приплъзване се използват за теоретични и практически изследвания в областта на семепроизводството и за обосноваване на конструктивните параметри на палцевите обезкрилители с непрекъснато действие.</span></span></p>', '<p>\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">The slipping between seeds is a typical and necessary of dewinging process with unceasing dewingers. The more slipping is bringing to be increasing a completeness of dewinging. In the same time this sleeping reduces productivity. Study for finding the coefficients of slipping between Scotland pine (Pinus silvestris), Austrian black pine (Pinus nigra) and Norwegian spruce (Picea excelsa) seeds are provided.<br />\r\n	Empirical equation for determining productivity is propounded. Working is performed at a plant for coniferous seeds processing (town of Razlog) with “Nordmark” dewinger. The coefficients are in dependence of the seeds pressure and revolutions of the screw. The received coefficients are intended for determining of productivity and completeness of dewinging<br />\r\n	with unceasing dewinging machines.</span></span></p>\r\n', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Константин Маринов</span></spa', '<p>\r\n	<span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Konstantin Marinov</span></span></p>\r\n', '1-2_2007_4.pdf', '2', '1'),
  ('13', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">СЪСТОЯНИЕ И ЗАПАСИ НА ДИВАТА КОЗА (<em>RUPICAPRA RUPICAPRA BALCANICA</em>, BOLKAY, 1925) В ЦЕНТРАЛНА СТАРА ПЛАНИНА</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">CHAMOIS’S STATEMENT AND RESERVE IN CENTRAL BALKAN MOUNTAIN</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Ограничаването на антропогенните фактори, като дърводобив, строителство, пасищно животно-въдство и бракониерство са основните причини за постепенното стабилизиране на популацията от дива коза, обитаваща централните части на старопланинската верига. Сигурни показатели за това са постепенното увеличаване на запаса и разширяване на териториите, които тя заема. Началото на ХХІ в. е времето, в което човешката дейност, започва да оказва все по-малко отрицателно влияние върху популацията от дива коза. Осъзнавайки това, местното население започва все по-активно да сътрудничи и взема участие в тези процеси.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Decreased influence of anthropogenic factors such as: woodcutting, construction, grazing grounds and poaching occur the main reasons for the gradually stabilization for the Chamois’ population inhabited Central parts of The Balkan.<br>The certain sign for that are the gradually stock increasing and extension of inhabited area. The beginning of the XXI century is the time, when the human activities begin to show lesser and lesser influence over the Chamois population. Conscious of that the native people start to collaborate more and more and participate in these activities.</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Росен Андреев</span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Rosen Andreev</span></span></p>', '1-2_2007_5.pdf', '2', '0'),
  ('14', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">ЕНЗИМНА АКТИВНОСТ НА АНТРОПОГЕННИ ПОЧВИ, РАЗПОЛОЖЕНИ НА ТЕРИТОРИЯТА НА СОФИЙСКА ГОЛЯМА ОБЩИНА</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">ENZYME ACTIVITY OF THE ANTHROPOGENIC SOILS ON THE TERRITORY OF SOFIA MUNICIPALITY</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Проучена е ензимната активност на почви в гр. София с високо техногенно натоварване. Влиянието на замърсената урбанизирана среда върху ензимната активност на градски почви е установено чрез изследване на протеазна и целулазна активност на почвата. Резултатите показват, че активността на изследваните ензими може да бъде използвана като индикатор за биологичното състояние на почвите в градски условия. Основна роля в процесите на самоочистване на почвите от замърсители има протеазната активност на почвените микроорганизми. Целулазната активност е лимитирана в условия на антропогенно натоварване.</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">The enzyme activity of the soils in Sofia with too high techno genetic pressure has been examined. The influence of the polluted urban environment to the enzyme activity of urban soils is determined by examination of protease and cellulase activity of the soil. The results show that the examined enzyme activity can be used as indicator for biological condition of the soils in urban conditions. Main role in the self-cleaning process of the soils from polluters has the protease activity of the soil microorganisms. The cellulase activity is limited in conditions of anthropogenic pressure.</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Бойка Малчева, Мая Нусторова</', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Boika Zdravkova Malcheva,Maya ', '1-2_2007_6.pdf', '2', '0'),
  ('15', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">ИНТЕНЗИВНОСТ НА РУШЕНЕТО НА МЕЛНИШКИТЕ ПИРАМИДИ</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">MELNIK PYRAMIDS DESTRUCTION INTENSITY</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Мелнишкият район е най-силно засегнатият от денудация район в страната. Продължителното съвместно действие на процесите на ерозия, срутване и свличане е създало живописни релефни форми с високи вертикални и урвести откосни повърхности – „пирамиди”.<br>Интензивността, с която се рушат откосните ръбове на пирамидите е определена въз основа на скъсяването на разстоянието между крайните точки на 93 профила за период от 45–47 години. Едната от точките е репер. Разграничават се реални репери – пътеки, върхове, триантулачни точки и др. и условни репери – откосните ръбове на ровини.<br>Първото измерване е направено по топографски карти от 1960 и 1961 г., а второто – по фотопланове от 2006 г. или директно на терена през 2007 година.<br>Установената максимална интензивност на денудационните процеси е 0,30 m/год. Обособени са следните четири групи пирамиди със съответната интензивност:<br>• І група - слаба интензивност до 0,05 m/год.;<br>• ІІ група - средна интензивност 0,06 – 0,15 m/год.;<br>• ІІІ група - силна интензивност над 0,15 m/год.</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">The Region of Melnik is the most severely denudation affected one in Bulgaria. The continuous joint influence of erosion, collapse and sliding of groundmasses has createdpicturesque relief forms of high vertical and overhanging escarpment surfaces known as “pyramids”.<br>The intensity of destroying these pyramids escarpment surfaces has been determined on the basis of shortening the distances between the two of points in each of 93 profiles for a 45–47 - year period. One of the points in each such couple is a landmark. Two kinds of landmark are distinguished-real, i.e. paths, peaks, triangulation points, etc., and conditional, i.e. escarpment edges of gullies.<br>The first measurement was done while using topographic maps of 1960 and 1961, and the second one - by means of photographic plans of 2006, or directly in the field, in 2007.<br>The maximum intensity of the denudation processes was found to be 0,30 m per year. The following four groups of pyramids have been differentiated according to their destruction intensity.<br>Group I – low intensity – up to 0,05 m per year;<br>Group II – moderate intensity – from 0,06 to 0,15 m per year;<br>Group III – high intensity – over 0,15 m per year.</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Димитър Зъков, Добринка Зъкова', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Dimitar Zakov, Dobrinka Zakova', '1-2_2007_7.pdf', '2', '0'),
  ('16', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">МАНАСТИРСКИТЕ КОМПЛЕКСИ – ОБЕКТИ С ВЪЗМОЖНОСТИ ЗА ОТДИХ И АЛТЕРНАТИВЕН ТУРИЗЪМ</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">THE MONASTERY COMPLEXES – OBJECTS OFFERING OPPORTUNITIES FOR RECREATION AND ALTERNATIVE TOURISM</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">В последните години се наблюдава повишен туристически интерес към българските манастири, които са тясно свързани с историческата съдба на страната и българския народ. От самото си създаване те се превръщат в центрове на славянската писменост и култура, съхраняващи националните ценности през трудни за държавата периоди, и същевременно до голяма степен оказват влияние и върху формирането на самобитния български архитектурен стил в отделните периоди.<br>Някои от манастирите датират още от византийско време и са спомогнали за запазването на българския дух през 5-те века Османско владичество, а други са построени в последните години на миналия век на мястото на разрушени обители, но почти винаги изграждането им е свързано с увлекателни истории и легенди. Поради набезите на османските поробители или просто заради неумолимите последици на времето, само малка част от сега действащите манастири са запазили първоначалния си облик. Въпреки това посещението на всеки от тях остава траен спомен, и помага да се докоснем до същината на българския бит, традиции и природа. Някои впечатляват с уникалната си архитекрура, други – с ценните си икони и майсторски стенописи, а трети – с разположението си сред най-живописните кътчета на страната</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">In the recent years an increasing tourist’s interest towards the Bulgarian monasteries, which are closely connected to the historical fate of the country and the Bulgarian people, is observed. From their very foundation they turned to be centers of the Slavonic education and culture, preserving the national treasures through periods of hardship for the country. At the same time the monasteries influence to a great extent the formation of the unique Bulgarian architectural style in the different periods.<br>Some of the monasteries date back to Byzantine times. They contributed to the preservation of the Bulgarian spirit during the five centuries of Ottoman rule. Others were built in the last years of the past century at the places of demolished cloisters but almost always their construction is related to intriguing stories and legends. Because of the raids of the Ottoman enslavers or just because of the inexorable consequences of time only a small number of the monasteries that are active nowadays have preserved their original appearance. Despite all that, a visit to each one of them leaves lasting memories and helps us feel the essence of the Bulgarian traditional lifestyle, customs and nature. Some impress with their unique<br>architecture; others - with their valuable icons and exquisite frescos; yet third impress because<br>they are located in the most picturesque spots of the country.<br>The purpose of the present analysis is not to provide a complete survey of all preserved monasteries located within the territory of Bulgaria because there are more than 150 of them.<br>The main ambition is to present those monasteries that have value for the tourists either because of their beautiful architecture, or their rich history, or the opportunity for a pleasant rest presented by the monastery complex, or the remarkable landscape that surrounds them.</span></span></p>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Веселин Рангелов</span></span>', '<p><span style=\"font-size: small;\"><span style=\"font-family: Tahoma;\">Veselin Rangelov</span></span>', '1-2_2007_8.pdf', '2', '0'),
  ('17', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\"><span style=\"mso-fareast-font-family: \'Times New Roman\'; mso-ansi-language: BG; mso-fareast-language: BG; mso-bidi-language: AR-SA\">35 ГОДИНИ ОБУЧЕНИЕ ПО „ЕКОЛОГИЯ И ОПАЗВАНЕ НА ОКОЛНАТА СРЕДА” В ЛЕСОТЕХНИЧЕСКИЯ УНИВЕРСИТЕТ, СОФИЯ</span></span></span></p>', '', '<p>Уважаеми колеги и гости,<br>Опазването и възстановяването на околната среда са едни от основните приоритети в развитието на съвременното общество, които изискват кадрови потенциал, подготвен на високо професионално ниво.<br>Това е особено важно днес – в условията на глобализиращия се свят, в условията на пазарна икономика и евроинтеграция, когато България е равноправен член на Европейския съюз. Страната ни търси своята идентичност в голямото европейско семейство и интеграция на българското висше образование в световната научна и образователна дейност. Нашият „влог” в европейското и световното пространство е високото образователно ниво на българската нация, показала на света, че България е раждала, ражда и ще ражда таланти. ...</p>', '', '<p>чл. кор. проф. дан арх. Атанас Ковачев, декан на Факултета по екология и ландшафтна архитектура</p>', '', 'Forestry_Ideas_BG_2009_15_1_1.pdf', '3', '4'),
  ('18', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">СУКЦЕСИОННИ ПРОЦЕСИ СЛЕД ВЕТРОВАЛ НА ДЪРВОСТОЯ НА ТЕРИТОРИЯТА НА УОГС „Г. АВРАМОВ” – ЮНДОЛА</span></span><o:p></o:p></p>', '<p>\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Arial,Helvetica,sans-serif;\">SECONDARY SUCCESS ION FOLLOWING WINDFALL ON THE TERRITORY OF STUDY AND TRAINING FORESTRY RANGE „G. AVRAMOV” – YUNDOLA</span></span><o:p></o:p></p>\r\n', '<p>В постоянни опитни площи са проследени сукцесионни процеси, протекли в периода 1995–2007 г. Установени и анализирани са показателите: темп на сукцесиите; промени във флористичния състав и промени в обилието на видовете. Установено е, че скоростта на промяната на видовия състав намалява във времето. Този процес е по-ясно изразен в групата на храстите и многогодишните тревисти растения. Средното обилие при отделните биологични типове не се променя съществено с изключение на многогодишните треви, чието обилие е намаляло значително. Може да се очаква увеличаване на обилието на храстите и дърветата и намаляване на обилието на двугодишните и едногодишните треви в резултат на променящата се фитоценотична среда. Продължаващите промени в състава и обилието на видовете показват, че във ветровалните площи протичат забавени сингенетични процеси, като първи етап от вторична сукцесия.</p>', '<p>\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Arial,Helvetica,sans-serif;\">Secondary succession for the period 1995–2007 has been observed in permanent plots. The following measures were established and analyzed: rate of succession, species composition change and abundance. We found that the species’ compositional change is slowing down in time. This process is more obvious in the shrub and perennial groups. Mean abundance through different life forms remains unchanged, excluding perennial herbs, which abundance is significantly lower. As a result of the changing environment, we should expect an increase in shrub and tree abundance and decrease in annual and biennial herbs. Continuous changes in composition and abundance show that the windfall areas are in the establishment phase, which is the first stage of the secondary forest succession.</span></span></p>\r\n', '<p>Мариус Димитров, Николай Дяков</p>', '<p>\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Arial,Helvetica,sans-serif;\">Marius Dimitrov, Nikolay Dyakov</span></span></p>\r\n', 'Forestry_Ideas_BG_2009_15_1_2.pdf', '3', '2'),
  ('19', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ФЛОРИСТИЧНИ ИЗСЛЕДВАНИЯ В СЪОБЩЕСТВАТА НА ОБИКНОВЕН КЕСТЕН (<em>CASTANEA SATIVA</em> MILL.)&#160; В РАЙОНА НА ЗАПАДНА СТАРА ПЛАНИНА</span></span><o:p></o:p></p>', '<p>\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Tahoma;\"><span>FLORISTIC INVESTIGATIONS OF THE CHESTNUT (<em>CASTANEA SATIVA </em>MILL.) COMMUNITIES IN THE WEST BALKAN REGION</span></span></span></p>\r\n', '<p>През последните десетилетия състоянието на кестеновите гори се влошава в глобален мащаб. То се изразява в преждевременно съхнене, нападение от болести, вредители и полупаразити. Смята се, че у нас основните причини за това са напредналата възраст, неправилното стопанисване и някои заболявания – главно ракът по кестена и мастилената болест. За изясняване на основните фактори, които го предизвикват, започват множество изследвания, провеждат се редица международни, регионални и национални конференции и съвещания.<br>Настоящото проучване е част от изследванията на структурата на тези съобщества у нас. Изследван е флористичният състав на находището от обикновен кестен (Castanea sativa Mill.) в района на Западна Стара планина, гр. Берковица. Установени са 139 вида висши растения, за които е определен биологичният тип, жизнената форма (по Raunkier) и флорните елементи (по Асьов и кол., 2002).<br>Направен е сравнителен флористичен анализ с кестеновите гори в планините Беласица и Славянка.<br>За картиране и анализ на разпространението на кестена е използвана ГИС , която позволява изработването на справки, заявки, както и съставяне на тематични карти.</p>', '<p>\r\n	The conditions of the chestnut forests were worsening in a global scale during the last decades. It was manifested in prematurely defoliation, drying-up, development of semiparasites, diseases and pests. It was consider that in Bulgaria the main causes for this were old age, wrong sylviculture management and some diseases – mainly Phytophtora cimiamoni Pand., Ph. cambivora Bnis. and Cryphonectria parasitica Murr. The great number of investigations had been started for the clarifying of the main factors which provoke it. A set of international, regional and national conferences were carried out.<br />\r\n	The present research was part of the investigations of the structure of these communities in Bulgaria. The floristic composition of the chestnut communities (Castaneta sativae) along West Balkan mountains was investigated in the present paper. A total of 139 species of vascular plants were described. The structure of the studied flora based on biological type, life form (17) and floristic elements (4) was determined.<br />\r\n	The comparative floristic analysis between the chestnut forests in Belasitsa and Slavianka mountain has been made.<br />\r\n	GIS was used for mapping and spatial analysis of chestnut formation areas. GIS applications allow performing SQL queries and criteria look-ups and assembling of thematic maps.</p>\r\n', '<p><em>Виолета Димитрова, Марияна Любенова , Мария Асенова</em></p>', '<p>\r\n	<em>Violeta Dimitrova, Mariyan Lyubenova, Maria Asenova</em></p>\r\n', 'Forestry_Ideas_BG_2009_15_1_3.pdf', '3', '4'),
  ('20', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\"><span style=\"mso-fareast-font-family: \'Times New Roman\'; mso-ansi-language: BG; mso-fareast-language: BG; mso-bidi-language: AR-SA\">ДИНАМИКА НА МАКРОЕЛЕМЕНТИ В ЛИСТАТА НА ДЪРВЕСНИ ВИДОВЕ В ДЕНДРАРИУМ „ПИСМЕНОВО”</span></span></span></p>', '<p>\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Arial,Helvetica,sans-serif;\">DYNAMICS OF MACROELEMENTS IN THE LEAVESIN THE TREE SPECIES GROWING IN PISMENOVO DENDRARY (DENDRARIUM)</span></span></p>\r\n', '<p>Дендрариумът е разположен в периферния подрайон на Странджа на територията на ДГС Царево. Проучвана е почвената влага на 10, 30, 50, 80 и 100 сm под 15–20-годишни насаждения от черен бор, атласки кедър, обикновен кипарис, източен горун, цер, благун, източен бук и летен дъб през периода 2004–2008 г.<br>Установено беше, че влажността на почвата в 100 сm почвен слой през вегетационния период зависи преди всичко от количеството на падналите валежи през изминалия есенно-зимен период. Влагозапасяването на почвата в началото на вегетационния период е високо и през 5-те години. През май и юни намалява силно поради интензивния растеж на дърветата и остава сравнително ниско до края на вегетационния период. През 2007 г. при някои от видовете (атласки кедър, обикновен кипарис, черен бор) влагата в повърхностните 30 cm намалява много рязко още през май. Особено ниска е тя през летните месеци, когато за слой 0-10 cm пада под ВТУ и се увеличава едва през ноември.<br>Различията между почвената влага в парцелите с различни дървесни видове не са големи. При иглолистните най-ниска е почвената влажност под обикновения кипарис и атлаския кедър (видовете с най-интензивен растеж), а при широколистните - под цера</p>', '<p>\r\n	This dendrary is situated within the peripheral sub-region in the Mountain of Strandzha, on the territory of the State Forestry of Tsarevo. Nitrogen and macroelements conets have been examined in the leaves of 16–20-year old tree species as Pinus nigra Arn. Ssp. Austriaca Höss, Pinus nigra Arn ssp. Iaricio Poiret, Cedrus deodara Loud., Cedrus atlantica Man. Cedrus libani Laws., Cypressus semepervirens L., 3 origins of Quercus petraea Liebl., 4 origins of Quercus robur L., Quercus pubescens Willd., Quercus rubra L., Quercus suber L., Quercus harwissiana Stev., Quercus frainetto Ten., Fagus silvatica L., Fagus orientalis Lipsky and Tilia argentea Desf, within the period as from 2004 up to 2007.<br />\r\n	N content in the leaves of the most of the deciduous species is the greatest in June, maintaining comparatively high values in July and gradually lowering in the further months, when the vegetation period occurs. In October, N concentration in the leaves of some of the species drops to a half of its previous value. P2O5 content is at its maximum value in the summer months, keeping its relatively high values by the end of the vegetation period. K2O concentration in the leaves of the most of the species is the highest in August. Ca and Mg contents is characterized by an increase from the beginning to to end of the vegetation period.<br />\r\n	N, P2O5 and K2O contents in the coniferous species is about 2 times lower as compared to that one, found out in the leaves of the deciduous species, and it is that same which makes the latter ones more unpretentious to soil fertility. The lowest is the concentration in the needles of the Atlas cedar species (Cedrus atlantica Man.). The highest is the content in the leaves of the silver-leaf lime tree (Tilia argentea Desf.) and in those ones of the oak species growing in the mountain of Strandzha while the lowest one results in the leaves of the corkwood (cork oak). There are also differences observed among the single origins within a definite species.<br />\r\n	No significant differences have been found out between the coniferous and deciduous species, as regards to Ca and Mg contents. It has been noted, Mg and Ca concentrations in the cedar needles results twice higher approximately than that one found out in the black pine needles.</p>\r\n', '<p><em>Мария Брощилова, Костадин Брощилов</em></p>', '<p>\r\n	<em>Maria Broshtilova, Kostadin Broshtilov</em></p>\r\n', 'Forestry_Ideas_BG_2009_15_1_4.pdf', '3', '3'),
  ('21', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ФЛОРА И РАСТИТЕЛНОСТ НА РУДНИК „КРЕМИКОВЦИ“</span></span><o:p></o:p></p>', '<p style=\"margin: 0mm 0mm 0pt\"><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">FLORA AND VEGETATION OF THE KREMIKOVTSI MINE</span></span></p>', '<p>Флората на рудник „Кремиковци” включва 74 вида, 62 рода и 24 семейства. С най-много представители са семейства Asteraceae (24), Poaceae (10) и Fabaceae (5). Семейства Boraginaceae, Chenopodiaceae, Salicaceae and Scrophulariaceae са представени с по 3 вида, семейства Apiaceae, Equisetaceae, Lamiaceae и Polygonaceae са представени с по 2 вида, а Euphorbiaceae, Juncaceae, Onagraceae, Papaveraceae, Pinaceae, Plantaginaceae, Ranunculaceae, Resedaceae, Rosaceae, Simarubiaceae и Vitaceae – с по 1 вид.</p>', '<p>The flora of the Kremikovtsi Mine comprises 74 species, 62 genera and 24 families. Asteraceae (24), Poaceae (10) and Fabaceae (5) are the most numerous families. Boraginaceae, Chenopodiaceae, Salicaceae and Scrophulariaceae have 3 species each. Apiaceae, Equisetaceae, Lamiaceae and Polygonaceae have 2 species each. Euphorbiaceae, Juncaceae, Onagraceae, Papaveraceae, Pinaceae, Plantaginaceae, Ranunculaceae, Resedaceae, Rosaceae, Simarubiaceae and Vitaceae have 1 species each.</p>', '<p><em>Васил Вутов, Димитър Димитров</em></p>', '<p><em>Vasil Vutov, Dimitar Dimitrov</em></p>', 'Forestry_Ideas_BG_2009_15_1_5.pdf', '3', '3'),
  ('22', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\"><font color=\"#221e1f\"><font color=\"#221e1f\"><span style=\"font-size: small\"><span style=\"font-family: Tahoma\"><font color=\"#221e1f\"><font color=\"#221e1f\"><p><span style=\"font-size: small\"><span style=\"font-family: Tahoma; color: #221e1f\">ФЛОРИСТИЧНА КЛАСИФИКАЦИЯ НА ДЪБОВИТЕ ГОРИ В ЗАПАДНИ ГРАНИЧНИ ПЛАНИНИ</span></span><span style=\"font-family: Tahoma; color: #221e1f\"><font size=\"3\"><o:p></o:p></font></span></p></font></font></span></span></font></font></span></span></p>', '<p>\r\n	<font color=\"#221e1f\"><font color=\"#221e1f\"><span style=\"font-size: small\"><span style=\"font-family: Tahoma; color: #221e1f\">FLORISTIC CLASSI</span><span style=\"font-family: Tahoma\"><font color=\"#000000\">F</font><span style=\"color: #221e1f\">ICATION O</span><font color=\"#000000\">F</font><span style=\"color: #221e1f\">OAK </span><font color=\"#000000\">F</font><span style=\"color: #221e1f\">ORESTS IN THE WEST FRONTIER MOUNTAINS</span></span></span></font></font></p>\r\n', '<p align=\"left\"></p><p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\"><font color=\"#221e1f\"><font color=\"#221e1f\">Обект на изследване са дъбовите гори в планините на Югозападна България – </font></font>О<font color=\"#221e1f\"><font color=\"#221e1f\">гражден, </font></font>М<font color=\"#221e1f\"><font color=\"#221e1f\">алешевска и </font></font>В<font color=\"#221e1f\"><font color=\"#221e1f\">лахина. На базата на 243 фитоценотични описания е предложена синтаксономична схема на съобществата. </font></font>О<font color=\"#221e1f\"><font color=\"#221e1f\">писани са 8 групи, представени в синоптична таблица. </font></font>В<font color=\"#221e1f\"><font color=\"#221e1f\">ъз основа на извършен флористичен и синтаксономичен анализ 3 от тях са отнесени към описани вече асоциации – </font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Querco cocciferae–Carpinetum orientalis </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">Oberdorfer 1948 еm. Horvat 1954, </font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Digitali viridiflorae–Quercetum frainetto </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">Gamisans et Herbard 1980, </font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Genisto carinalis–Quercetum petraeae </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">Bergmeier in Bergmeier et Dimopoulos 2008. Описани са две нови асоциации – </font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Cisto incani–Quercetum pubescentis</font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">, </font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Cyclamini hederifoli–Quercetum frainettо </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">и три групи съобщества – </font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Cephalanthera rubra–Quercus pubescens, Theucrium polium–Quercus pubescens, Vicia cracca–Quercus frainetto. </font></font></font></i></i></i></i></i></i></span></span></p>', '<p style=\"text-align: justify;\">\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Arial,Helvetica,sans-serif;\"><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Querco cocciferae–Carpinetum orientalis </font>Oberdorfer 1948 еm. Horvat 1954, </font></font><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Digitali viridiflorae–Quercetum frainetto </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">Gamisans et Herbard 1980, </font></font><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Genisto carinalis–Quercetum petraeae </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">Bergmeier in Bergmeier et Dimopoulos 2008. Two new associations – </font></font><font color=\"#221e1f\"><font color=\"#221e1f\"><font color=\"#221e1f\">Cisto incani–Quercetum pubescentis, Cyclamini hederifoli–Quercetum frainettо </font></font></font><font color=\"#221e1f\"><font color=\"#221e1f\">and three communities – <font color=\"#221e1f\">Cephalanthera rubra–Quercus pubescens, Theucrium polium–Quercus pubescens, Vicia cracca–Quercus frainetto </font>are established</font></font><i><font color=\"#221e1f\"><font color=\"#221e1f\">.</font></font></i></span></span></p>\r\n<p style=\"text-align: justify;\">\r\n	<span style=\"font-size: 11px;\"><span style=\"font-family: Arial,Helvetica,sans-serif;\">The object of this research are the oak forests in three mountains in Southwest Bulgaria – Ograjden, Maleshevska mountain and Vlahina. A new syntaxonomic scheme of the communities has been suggested on the basis of 243 phytocoenotic relevés. The paper provides a description of 8 groups in a synoptic table. On the basis of a syntaxonomic analysis 3 of them have been classified to belong to the following associations which have already been described:</span></span></p>\r\n', '<p align=\"left\"><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Георги Гогушев</span></span></p>', '<p>\r\n	<span style=\"font-size: 11px;\"><em><span style=\"font-family: Tahoma;\">Georgi Gogushev</span></em></span></p>\r\n', 'Forestry_Ideas_BG_2009_15_1_1.pdf', '3', '4'),
  ('23', '<p>ПРИНОС КЪМ ПРОУЧВАНЕ НА РАСТИТЕЛНИТЕ ХАБИТАТИ В ЗАПАДЕН ЕДБАЛКАН<br>И ЗАПАДНА СТАРА ПЛАНИНА</p>', '<p>A CONTRIBUTION TO THE INVESTIGATION OF PLANT HABITATS IN THE WEST PART OF PREDBALKAN AND BALKAN RANGE, BULGARIA</p>', '<p>Проведени са теренни изследвания в два флористични района на България – Предбалкан&#160; (Западен) и Стара планина (Западна) през лятото на 2005 г. Полигоните са разположени в планините: Драгойца, Лакавица – Предбалкан (Западен) и Ржана, Голема, Мала, Софийска, Мургаш и Било – Стара планина (Западна). В проучените 45 полигона са описани 43 хабитата, които принадлежат към 8 типа. Най-широко застъпени са хабитатите, отнасящи се към следните 3 типа: 6510, 6210 и 6520. Описани са 24 хабитати, по-типични за изследваните райони. Установена е висока степен на биоразнообразие в районите, което се нуждае от защита.</p>', '<p>A field exploration in two floristic regions of Bulgaria – Predbalkan (West) and Balkan Range (West) has been carried out in summer 2005. The experimental plots are located in the mountains of Predbalkan (West) – Dragoytsa, Lakavitsa and Balkan Range (West) – Rzhana, Golema, Mala, Sofiyska, Murgash and Bilo. Within the 45 investigated plots 43 plant habitats, belonging to 8 types, were described. The habitats from the following 3 types: 6510, 6210 and 6520 are the most widespread. 23 habitats, more typical for the investigated regions, were described. A high level of biodiversity in the regions was detected which needs conservation.</p>', '<p>Димитър Димитров, Maйя Куртева</p>', '<p>Dimitar Dimitrov, Maya Kurteva</p>', 'Forestry_Ideas_BG_2009_15_1_7.pdf', '3', '3'),
  ('24', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\"><span style=\"mso-fareast-font-family: \'Times New Roman\'; mso-ansi-language: BG; mso-fareast-language: BG; mso-bidi-language: AR-SA\">ФЛОРА И РАСТИТЕЛНОСТ НА ЗМ „БЛАТАТА КРАЙ СЕЛО ДОЛНИ БОГРОВ“</span></span></span></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">FLORA AND VEGETATION OF THE SWAMPS NEAR THE VILLAGE OF DOLNI BOGROV PROTECTED AREA</span></span><o:p></o:p></p>', '<p>Флората на „Блатата до село Долни Богров” включва общо 162 вида висши растения от 130 рода и 50 семейства. С най-много представители са семейства&#160; Asteraceae (19),&#160; Brassicaceae (14), Fabaceae (12), Poaceae (12), Caryophyllaceae (7), Lamiaceae (7), Rosaceae (7), Apiaceae (5), Cyperaceae (5) и Salicaceae (5). Доминиращи в растителността на защитената територия са съобществата на&#160; Potamogenetumи Myryophylletum.</p>', '<p>The flora of the „Sw amp near the vill age of Dolni Bogrov” comp ris es a total of 176 vasc ular pl ants from 138 genera and 52 famili es. The most numerous famili es are Asteraceae (19), Brassic aceae (15), Fabaceae (14), Poaceae (13), Caryophyll aceae (7), Lami aceae (7), Rosaceae (7), Api aceae (6), Cyperaceae (7) Salic aceae (5). The vegetations in the protected area is domin ated by the Phragmi tetum, Potamogenetum, and the Myryophyll etum water communities.</p>', '<p><em><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Димитър Димитров, Васил Вутов</span></span></em></p>', '<p><em><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Dimitar Dimitrov, Vasil Vutov</span></span></em></p>', 'Forestry_Ideas_BG_2009_15_1_8.pdf', '3', '0'),
  ('25', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ЕКОЛОГИЧНИ ПРОУЧВАНИЯ В БИОСФЕРЕН РЕЗЕРВАТ „ЧУПРЕНЕ”</span></span><o:p></o:p></p>', '<p><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">ECOLOGICAL SURVEY IN CHUPRENE BIOSPHERE RESERVE</span></span><o:p></o:p></p>', '<p>Резерват „Чупрене” е един от 16-те резервата в България, признати за биосферни в рамките на програмата на ЮНЕСКО „Човек и биосфера”. Една от основните функции на тази категория защитена територия е провеждането на научни изследвания и екологичен мониторинг. В представителни за резерватната територия смърчови насаждения са заложени пробни площи и са взети проби от мъртва горска постилка, почви и иглолиста от смърч. Анализирано е съдържанието на макро- и микроелементи и са оценени почвеното плодородие, устойчивостта на почвите към замърсяване и минералното хранене.<br>Ключови думи: биосферен резерват, почвено плодородие, микро- и макроелементи, листен анализ.<br></p>', '<p>Chuprene Biosphere Reserve is among the 16 biosphere reserves established in Bulgaria under UNESCO&#160; „Ma n and Biosphere” Programme. Some of the main functions of this protected area ca tegory are ecologica l surveys and monitoring of the environment. In the present paper results for mac ro- and microelement content in soil samples, litter and needles in representative spruce stands were presented and discussed. In addition soil fertility and soil resistance to pollution were assessed.</p><p>Keywords : Biosphere</p>', '<p><em>Дилянка Безлова, Людмила Малинова, Десислава Томова</em></p>', '<p><em>Dilyanka Bezlova, Ludmila Malinova, Desislava Tomova</em></p>', 'Forestry_Ideas_BG_2009_15_1_9.pdf', '3', '0'),
