\"1\">\r\n </o:shapelayout></xml><![endif]--></p><p class=\"MsoNormal\"><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Характеризирана е систематичната структура на медоносните растения от висшата флора на България. На основата на критичен анализ на литературни източници е съставен пълен списък на медоносните растения, срещащи се естествено в България. Към тази група са отнесени 563 вида от 230 рода и 74 семейства. Представени са семействата и родовете с най-много медоносни растения. Изследваните видове са разделени на 3 групи – растения, от които пчелите използват само цветен прашец, видове от които пчелите използват само нектар и видове, от които пчелите използват и двете. За първи път е представен пълен систематичен списък на диворастящите медоносни растения в България.</span></span></p><p class=\"MsoNormal\"><span style=\"font-size: small\"><span style=\"font-family: Tahoma\">Ключови думи: България, флора, систематична структура, медоносни растения.</span></span></p>', '<meta content=\"text/html; charset=utf-8\" http-equiv=\"Content-Type\" />\r\n<meta content=\"Word.Document\" name=\"ProgId\" />\r\n<meta content=\"Microsoft Word 12\" name=\"Generator\" />\r\n<meta content=\"Microsoft Word 12\" name=\"Originator\" />\r\n<link href=\"file:///C:%5CUsers%5CVasil%5CAppData%5CLocal%5CTemp%5Cmsohtmlclip1%5C01%5Cclip_filelist.xml\" rel=\"File-List\" />\r\n<link href=\"file:///C:%5CUsers%5CVasil%5CAppData%5CLocal%5CTemp%5Cmsohtmlclip1%5C01%5Cclip_themedata.thmx\" rel=\"themeData\" />\r\n<link href=\"file:///C:%5CUsers%5CVasil%5CAppData%5CLocal%5CTemp%5Cmsohtmlclip1%5C01%5Cclip_colorschememapping.xml\" rel=\"colorSchemeMapping\" />\r\n<!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves>\r\n  <w:TrackFormatting>\r\n  <w:HyphenationZone>21</w:HyphenationZone>\r\n  <w:PunctuationKerning>\r\n  <w:ValidateAgainstSchemas>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixe