INSERT INTO `news_en` (`newsID`, `newsText`, `newsYear`, `newsDatum`) VALUES
  ('14', '<p align=\"center\" style=\"text-align: center; line-height: 15pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">\r\n	<strong><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">International Conference \'</span></span></span></strong><strong><span style=\"color:black;\">А</span></strong><em><strong><span style=\"font-style:normal;\"><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">century of forest knowledge</span></span></span></span></strong></em><em><strong><span style=\"font-style:normal;\"><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">–</span></span></span></span></strong></em><em><strong><span style=\"font-style:normal;\"><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">education, innovations, challenges\'</span></span></span></span></strong></em><strong><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">7–</span></span></span></strong><strong><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">9 May 202</span></span></span></strong><strong><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">5</span></span></span></strong><strong><span style=\"color:#003300;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.5pt;\">, Sofia, Bulgaria</span></span></span></strong></p>\r\n<p style=\"text-align: justify; line-height: 14pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">\r\n	<span style=\"color:black;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.0pt;\">University of Forestry</span></span></span><span style=\"color:black;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.0pt;\">,</span></span></span><span style=\"color:black;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.0pt;\">Sofia Bulgaria is happy to announce and to invite you to participate in the International Conference<em>\'</em><em><span style=\"font-style:normal;\">A century of forest knowledge – education, innovations, challenges’ (CENFORKNOW 2025)</span></em><em>, </em>which will take place on&nbsp;7</span></span></span><span style=\"color:black;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.0pt;\">–</span></span></span><span style=\"color:black;\"><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.0pt;\">9 May 2025&nbsp;in Sofia, Bulgaria. The Conference is dedicated to the 100th&nbsp;Anniversary of University Forestry Education in Bulgaria. See all information on Conference website:&nbsp;</span></span></span><span style=\"color:black;\"><a href=\"https://cenforknow2025.ltu.bg/\"><strong><span style=\"font-family:arial,sans-serif;\"><span style=\"font-size:10.0pt;\">https://cenforknow2025.ltu.bg</span></span></strong></a></span></p>\r\n', '2025', '24.01.2025'),
  ('9', '<p align=\"center\" style=\"text-align:center;\">\r\n	<span style=\"font-size: 14px;\"><cite><strong><span style=\"color:#003300;\">International Scientific Conference \'<em>Forestry: Bridge to the Future\':</em>&nbsp;</span></strong><strong><span style=\"color:#003300;\">7</span></strong><strong><span style=\"color:#003300;\">-</span></strong><strong><span style=\"color:#003300;\">9 May 2015, Sofia, Bulgaria</span></strong></cite></span></p>\r\n<p>\r\n	<span style=\"font-size: 12px;\"><span style=\"font-family: Arial, Helvetica, sans-serif;\">University of Forestry Sofia has the pleasure to invite you to participate in the International Scientific Conference \'<em>Forestry: Bridge to the Future\'</em>, which will take place on 6-9 May 2015 in Sofia, Bulgaria. The Conference is dedicated to the 90<sup>th</sup> Anniversary of higher forestry education in Bulgaria and is organized by the University of Forestry, Sofia and Faculty of Forestry.See all information on conference web-site: <span style=\"color:#000099;\"><a href=\"http://conf2015.forestry-ideas.info/\"><span style=\"color:#000099;\">http://conf2015.forestry-ideas.info</span></a></span></span></span></p>\r\n', '2024', '02.12.2024'),
  ('12', '<p align=\"center\" style=\"color: rgb(0, 0, 0); font-family: Arial, Helvetica, sans-serif; text-align: center;\">\r\n	<span style=\"font-size: 14px;\"><cite><strong><span style=\"color: rgb(0, 51, 0);\">International Scientific Conference \'<em>Forestry: Bridge to the Future\'</em> 6</span></strong><strong><span style=\"color: rgb(0, 51, 0);\">-</span></strong><strong><span style=\"color: rgb(0, 51, 0);\">9 May 2020, Sofia, Bulgaria </span><span style=\"color: rgb(255, 0, 0);\">- postponed to 5-8 May 2021</span></strong></cite></span></p>\r\n<p style=\"color: rgb(0, 0, 0); font-family: Arial, Helvetica, sans-serif; text-align: justify;\">\r\n	University of Forestry Sofia and Faculty of Forestry has the pleasure to invite you to participate in the International Scientific Conference \'<em>Forestry: Bridge to the Future\'</em>, which will take place on <del>6-9 May 2020</del> <span style=\"color: rgb(255, 0, 0);\">5-8 May 2021</span> in Sofia, Bulgaria. The Conference is dedicated to the 95<sup>th</sup>&nbsp;Anniversary of higher forestry education in Bulgaria and is organized by the University of Forestry, Sofia and Faculty of Forestry. See all information on conference web-site:&nbsp;<a href=\"https://conf2020.forestry-ideas.info/\" style=\"font-family: Arial, Verdana, sans-serif;\">https://conf2020.forestry-ideas.info/</a></p>\r\n', '2020', '12.04.2020'),
  ('10', '<p>\r\n	<span style=\"color:black;\"><span style=\"font-family:verdana,sans-serif;\"><span style=\"font-size:9.0pt;\">The issues 2/2014, 1/2015 and 2/2015 are financially supported by the National Science Fund, Competition \'Bulgarian Scientific Periodicals - 2014\', Ministry of Education and Science of Bulgaria.</span></span></span></p>\r\n', '2019', '24.07.2019'),
  ('11', '<p>\r\n	<span style=\"font-family:times new roman,serif;\"><span style=\"font-size:12.0pt;\">The Forestry Ideas has been evaluated for inclusion in Scopus by the Content Selection &amp; Advisory Board (CSAB). The review of the journal was completed in 2016 and the CSAB has advised that the title is accepted for inclusion in Scopus. For the status of SJR see:&nbsp;</span></span><a href=\"https://www.scimagojr.com/journalsearch.php?q=21100814514&amp;tip=sid&amp;clean=0\">https://www.scimagojr.com/journalsearch.php?q=21100814514&amp;tip=sid&amp;clean=0</a></p>\r\n', '2019', '24.07.2019'),
  ('15', '<p align=\"center\" style=\"text-align:center;\">\r\n	<strong>Special issue 2/2025 dedicated to the Conference ‘A century of forest knowledge – education, innovations, challenges (CENFORKNOW 2025)’ held on 7–9 May 2025 in Sofia</strong></p>\r\n<p style=\"margin-bottom:6.0pt;text-align:justify;\">\r\n	The Conference <strong>‘A century of forest knowledge – education, innovations, challenges (CENFORKNOW 2025)’, </strong>dedicated to the 100th anniversary of Higher forestry education in Bulgaria, took place from 7 to 9 May 2025 in Sofia, Bulgaria. The event brought together more than 160 participants from various countries.</p>\r\n<p style=\"margin-bottom:6.0pt;text-align:justify;\">\r\n	<strong>Manuscript submission:</strong>Conference participants are invited to submit their manuscripts to the following email address: <a href=\"mailto:ForestryIdeas@ltu.bg\">ForestryIdeas@ltu.bg</a>To be considered for inclusion in the special issue, please submit your manuscript by 1 July 2025.</p>\r\n<p style=\"margin-bottom:6.0pt;text-align:justify;\">\r\n	<strong>Peer review:</strong>All submitted manuscripts will undergo a rigorous peer-review process. Each paper willbe reviewed by at least two independent experts, including members of the Conference Scientific Committee and subject-matter specialists. This process ensures the quality, originality, and relevance of the work selected for publication.</p>\r\n<p style=\"margin-bottom:0cm;\">\r\n	<strong>Guest editors:</strong></p>\r\n<p style=\"margin-bottom:0cm;\">\r\n	Assoc. Prof. Stoyan Stoyanov, Forestry Faculty, University of Forestry in Sofia</p>\r\n<p style=\"margin-bottom:0cm;\">\r\n	Prof. Peter Zhelev, Forestry Faculty, University of Forestry in Sofia</p>\r\n<p style=\"margin-bottom:0cm;\">\r\n	Prof. Rumen Tomov, Agronomy Faculty, University of Forestry in Sofia</p>\r\n<p style=\"margin-bottom:0cm;\">\r\n	Assoc. Prof. Momchil Panayotov, Forestry Faculty, University of Forestry in Sofia</p>\r\n', '2025', '10.06.2025');
